    for char in invalid_chars:
        result = result.replace(char, '_')
    return result.strip() or 'unknown'


def task_label(task_name):
    return task_name.replace('_', '')


def task_score_col(task_name, score_col):
    return f'{task_label(task_name)}_{score_col}'


def avg_score_col(score_col):
    return f'平均_{score_col}'


def load_task_dataframe(task):
    df = pd.read_excel(task['input_path']).copy()
    for col in [STUDENT_ID_COL, STUDENT_NAME_COL, *SCORE_COLS]:
        if col not in df.columns:
            df[col] = np.nan

    df[STUDENT_ID_COL] = df[STUDENT_ID_COL].astype(str).str.strip()
    df[STUDENT_NAME_COL] = df[STUDENT_NAME_COL].astype(str).str.strip()

    original_m = safe_numeric(df['M'])
    submitted_mask = original_m.notna()

    for col in SCORE_COLS:
        df[col] = safe_numeric(df[col])

    df.loc[~submitted_mask, SCORE_COLS] = np.nan

    if not TASK_HAS_PROGRAMMING.get(task['name'], True):
        df[PROGRAMMING_COL] = np.nan

    renamed_cols = {
        col: task_score_col(task['name'], col)
        for col in SCORE_COLS
    }
    return df[[STUDENT_ID_COL, STUDENT_NAME_COL, *SCORE_COLS]].rename(columns=renamed_cols)


def merge_task_data(task_frames):
    merged_df = None
    for task_df in task_frames:
        if merged_df is None:
            merged_df = task_df
        else:
            merged_df = merged_df.merge(task_df, on=[STUDENT_ID_COL, STUDENT_NAME_COL], how='outer')
    if merged_df is None:
        merged_df = pd.DataFrame(columns=[STUDENT_ID_COL, STUDENT_NAME_COL])
    return merged_df.sort_values([STUDENT_ID_COL, STUDENT_NAME_COL]).reset_index(drop=True)


